CREATE EXTENSION IF NOT EXISTS pgcrypto;
DROP TABLE IF EXISTS attempt_answers CASCADE;DROP TABLE IF EXISTS attempts CASCADE;DROP TABLE IF EXISTS questions CASCADE;DROP TABLE IF EXISTS lessons CASCADE;DROP TABLE IF EXISTS topics CASCADE;DROP TABLE IF EXISTS levels CASCADE;DROP TABLE IF EXISTS tests CASCADE;DROP TABLE IF EXISTS users CASCADE;DROP TABLE IF EXISTS articles CASCADE;
CREATE TABLE users(id UUID PRIMARY KEY DEFAULT gen_random_uuid(),name TEXT,email TEXT UNIQUE,role TEXT DEFAULT 'student',xp INT DEFAULT 0,streak_days INT DEFAULT 0,created_at TIMESTAMPTZ DEFAULT now());
CREATE TABLE tests(id UUID PRIMARY KEY DEFAULT gen_random_uuid(),name TEXT NOT NULL,slug TEXT UNIQUE NOT NULL,short_name TEXT NOT NULL,description TEXT);
CREATE TABLE levels(id UUID PRIMARY KEY DEFAULT gen_random_uuid(),test_id UUID REFERENCES tests(id) ON DELETE CASCADE,level_no INT,title TEXT,description TEXT,passing_percentage INT DEFAULT 85);
CREATE TABLE topics(id UUID PRIMARY KEY DEFAULT gen_random_uuid(),level_id UUID REFERENCES levels(id) ON DELETE CASCADE,title TEXT,slug TEXT,category TEXT,order_no INT DEFAULT 1);
CREATE TABLE lessons(id UUID PRIMARY KEY DEFAULT gen_random_uuid(),topic_id UUID REFERENCES topics(id) ON DELETE CASCADE,title TEXT,content_md TEXT,source_reference TEXT,order_no INT DEFAULT 1);
CREATE TABLE questions(id UUID PRIMARY KEY DEFAULT gen_random_uuid(),test_id UUID REFERENCES tests(id),level_id UUID REFERENCES levels(id),topic_id UUID REFERENCES topics(id),question_text TEXT NOT NULL,option_a TEXT NOT NULL,option_b TEXT NOT NULL,option_c TEXT NOT NULL,option_d TEXT NOT NULL,correct_option CHAR(1) NOT NULL,explanation TEXT NOT NULL,difficulty TEXT DEFAULT 'medium',source_reference TEXT,is_verified BOOLEAN DEFAULT true);
CREATE TABLE attempts(id UUID PRIMARY KEY DEFAULT gen_random_uuid(),user_id UUID,test_id UUID,level_id UUID,mode TEXT,total_questions INT,correct_count INT,percentage INT,passed BOOLEAN,created_at TIMESTAMPTZ DEFAULT now());
CREATE TABLE attempt_answers(id UUID PRIMARY KEY DEFAULT gen_random_uuid(),attempt_id UUID REFERENCES attempts(id),question_id UUID REFERENCES questions(id),selected_option CHAR(1),is_correct BOOLEAN);
CREATE TABLE articles(id UUID PRIMARY KEY DEFAULT gen_random_uuid(),title TEXT,slug TEXT UNIQUE,content_md TEXT,status TEXT DEFAULT 'draft',created_at TIMESTAMPTZ DEFAULT now());
CREATE OR REPLACE VIEW dashboard_level_view AS SELECT l.id level_id,t.slug test_slug,t.short_name,l.level_no,l.title,l.description,l.passing_percentage,COUNT(q.id) FILTER(WHERE q.is_verified=true) verified_questions FROM levels l JOIN tests t ON t.id=l.test_id LEFT JOIN questions q ON q.level_id=l.id GROUP BY l.id,t.slug,t.short_name,l.level_no,l.title,l.description,l.passing_percentage ORDER BY l.level_no;
