INSERT INTO lessons(topic_id,title,content_md,source_reference) SELECT id,'Logical connectives','If A implies B, the valid equivalent is the contrapositive: not B implies not A. Do not reverse the statement.','Quick HAT Guide aligned concept' FROM topics WHERE slug='logical-connectives';
INSERT INTO lessons(topic_id,title,content_md,source_reference) SELECT id,'Ordering method','Draw a diagram first. Immediately before means no item is between the two elements.','Quick HAT Guide aligned concept' FROM topics WHERE slug='ordering-questions';
INSERT INTO lessons(topic_id,title,content_md,source_reference) SELECT id,'Number system','Natural, whole, integer, even, odd, prime and composite numbers are common HAT quantitative basics.','Quick HAT Guide aligned concept' FROM topics WHERE slug='number-system';
INSERT INTO questions(test_id,level_id,topic_id,question_text,option_a,option_b,option_c,option_d,correct_option,explanation,difficulty,source_reference,is_verified) SELECT t.id,l.id,tp.id,'If A implies B, which statement is logically equivalent?','B implies A','Not A implies Not B','Not B implies Not A','A and B are unrelated','C','The valid equivalent of A implies B is the contrapositive: not B implies not A.','medium','Quick HAT Guide aligned',true FROM tests t,levels l,topics tp WHERE t.slug='hat' AND l.test_id=t.id AND l.level_no=1 AND tp.level_id=l.id AND tp.slug='logical-connectives';
INSERT INTO questions(test_id,level_id,topic_id,question_text,option_a,option_b,option_c,option_d,correct_option,explanation,difficulty,source_reference,is_verified) SELECT t.id,l.id,tp.id,'In ordering questions, what does immediately before mean?','A can be anywhere before B','No element is between A and B','B is before A','A and B are separate groups','B','Immediately before means both items are adjacent with no item between them.','easy','Quick HAT Guide aligned',true FROM tests t,levels l,topics tp WHERE t.slug='hat' AND l.test_id=t.id AND l.level_no=1 AND tp.level_id=l.id AND tp.slug='ordering-questions';
INSERT INTO questions(test_id,level_id,topic_id,question_text,option_a,option_b,option_c,option_d,correct_option,explanation,difficulty,source_reference,is_verified) SELECT t.id,l.id,tp.id,'Which is the only even prime number?','1','2','4','6','B','2 is the only even prime number.','easy','Quick HAT Guide aligned',true FROM tests t,levels l,topics tp WHERE t.slug='hat' AND l.test_id=t.id AND l.level_no=2 AND tp.level_id=l.id AND tp.slug='number-system';
